class Base {
    void show() { System.out.println("Base"); }
}
class Derived extends Base {
    void show() { System.out.println("Derived"); }
    void extra() { System.out.println("Extra"); }
}
public class Main {
    public static void main(String[] args) {
        Base b = new Derived();
        b.show();
        if (b instanceof Derived) {
            ((Derived) b).extra();
        }
    }
}

